1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0], [1, 0],
6	  [-1, 1], [0, 1], [1, 1],
7	];
8	
9	const REPRODUCTION_COUNT = 3;
10	const SURVIVAL_COUNT = 2;
11	
12	const keyOf = (x: number, y: number): string => `${x},${y}`;
13	
14	function countLiveNeighbors(cells: Cell[]): Map<string, number> {
15	  const counts = new Map<string, number>();
16	  for (const [x, y] of cells) {
17	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
18	      const key = keyOf(x + dx, y + dy);
19	      counts.set(key, (counts.get(key) ?? 0) + 1);
20	    }
21	  }
22	  return counts;
23	}
24	
25	export function nextGeneration(cells: Cell[]): Cell[] {
26	  const living = new Set(cells.map(([x, y]) => keyOf(x, y)));
27	  const neighborCounts = countLiveNeighbors(cells);
28	
29	  const next: Cell[] = [];
30	  for (const [key, count] of neighborCounts) {
31	    const survives = count === SURVIVAL_COUNT && living.has(key);
32	    const reproduces = count === REPRODUCTION_COUNT;
33	    if (survives || reproduces) {
34	      const [x, y] = key.split(",").map(Number);
35	      next.push([x, y]);
36	    }
37	  }
38	  return next;
39	}
