1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	type Cell = [number, number];
5	
6	const sortCells = (cells: Cell[]): Cell[] =>
7	  [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
8	
9	describe("Game of Life - Next Generation", () => {
10	  it("returns empty for empty input — [] → []", () => {
11	    expect(nextGeneration([])).toEqual([]);
12	  });
13	  it("single live cell dies (0 neighbors) — [(0,0)] → []", () => {
14	    expect(nextGeneration([[0, 0]])).toEqual([]);
15	  });
16	  it("underpopulation: pair each with 1 neighbor dies — [(0,1),(1,1)] → []", () => {
17	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
18	  });
19	  it("survival: live cell with 2 neighbors lives on — center of vertical triple survives", () => {
20	    // Vertical triple: center (1,1) has 2 live neighbors → survives
21	    const result = nextGeneration([[1, 0], [1, 1], [1, 2]]);
22	    expect(result).toContainEqual([1, 1]);
23	  });
24	  it("overpopulation: live cell with >3 neighbors dies — center with 4 neighbors removed", () => {
25	    // Center (1,1) has 4 orthogonal live neighbors → overpopulation → dies
26	    const result = nextGeneration([[1, 1], [0, 1], [2, 1], [1, 0], [1, 2]]);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("reproduction: dead cell with exactly 3 neighbors becomes alive — (1,1) born", () => {
30	    // Dead cell (1,1) has 3 live neighbors (0,0),(1,0),(0,1) → born
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
32	    expect(result).toContainEqual([1, 1]);
33	  });
34	  it("block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
35	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
36	    const result = nextGeneration(block);
37	    expect(sortCells(result)).toEqual(sortCells(block));
38	  });
39	  it("blinker oscillates — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
40	    const gen0: Cell[] = [[0, 0], [0, 1], [0, 2]];
41	    const gen1: Cell[] = [[-1, 1], [0, 1], [1, 1]];
42	    expect(sortCells(nextGeneration(gen0))).toEqual(sortCells(gen1));
43	  });
44	  it("handles negative coordinates — block in negative space is unchanged", () => {
45	    const block: Cell[] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
46	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
47	  });
48	});
